import asyncio
import json
import math
import time
import uuid
from dataclasses import dataclass, field
from typing import Dict, List, Tuple, Optional

TICK_RATE = 20
DT = 1.0 / TICK_RATE
WORLD_W = 4000.0
WORLD_H = 4000.0
PLAYER_SPEED = 260.0
PLAYER_RADIUS = 18.0
VIEW_DISTANCE = 900.0
BULLET_SPEED = 1200.0
BULLET_LIFETIME = 1.5
FIRE_COOLDOWN = 0.12
MAX_HEALTH = 100
SERVER_HOST = "0.0.0.0"
SERVER_PORT = 8765

WALLS = [
    (800, 700, 1200, 760),
    (1500, 1400, 1560, 2200),
    (2200, 900, 3000, 960),
    (2600, 1800, 2660, 2800),
    (500, 2500, 1300, 2560),
]

def clamp(v, a, b):
    return a if v < a else b if v > b else v

def vec_len(x, y):
    return math.hypot(x, y)

def norm(x, y):
    l = math.hypot(x, y)
    if l == 0:
        return 0.0, 0.0
    return x / l, y / l

def dist2(ax, ay, bx, by):
    dx = ax - bx
    dy = ay - by
    return dx * dx + dy * dy

def segment_intersects_aabb(x1, y1, x2, y2, rx1, ry1, rx2, ry2):
    dx = x2 - x1
    dy = y2 - y1
    tmin = 0.0
    tmax = 1.0

    if abs(dx) < 1e-9:
        if x1 < rx1 or x1 > rx2:
            return False
    else:
        inv = 1.0 / dx
        t1 = (rx1 - x1) * inv
        t2 = (rx2 - x1) * inv
        if t1 > t2:
            t1, t2 = t2, t1
        tmin = max(tmin, t1)
        tmax = min(tmax, t2)
        if tmin > tmax:
            return False

    if abs(dy) < 1e-9:
        if y1 < ry1 or y1 > ry2:
            return False
    else:
        inv = 1.0 / dy
        t1 = (ry1 - y1) * inv
        t2 = (ry2 - y1) * inv
        if t1 > t2:
            t1, t2 = t2, t1
        tmin = max(tmin, t1)
        tmax = min(tmax, t2)
        if tmin > tmax:
            return False

    return True

def has_line_of_sight(ax, ay, bx, by):
    for x1, y1, x2, y2 in WALLS:
        if segment_intersects_aabb(ax, ay, bx, by, x1, y1, x2, y2):
            return False
    return True

def point_in_wall(x, y):
    for x1, y1, x2, y2 in WALLS:
        if x1 <= x <= x2 and y1 <= y <= y2:
            return True
    return False

def move_with_collision(x, y, nx, ny):
    nx = clamp(nx, 0, WORLD_W)
    ny = clamp(ny, 0, WORLD_H)
    if not point_in_wall(nx, y):
        x = nx
    if not point_in_wall(x, ny):
        y = ny
    return x, y

@dataclass
class Player:
    id: str
    name: str
    writer: asyncio.StreamWriter
    x: float
    y: float
    vx: float = 0.0
    vy: float = 0.0
    aim_x: float = 1.0
    aim_y: float = 0.0
    hp: int = MAX_HEALTH
    alive: bool = True
    last_fire: float = 0.0
    last_seq: int = -1
    pending_input: dict = field(default_factory=dict)

@dataclass
class Bullet:
    id: str
    owner_id: str
    x: float
    y: float
    vx: float
    vy: float
    ttl: float

class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.bullets: Dict[str, Bullet] = {}
        self.tick = 0
        self.lock = asyncio.Lock()

    async def send(self, writer: asyncio.StreamWriter, msg: dict):
        data = (json.dumps(msg, separators=(",", ":")) + "\n").encode()
        writer.write(data)
        await writer.drain()

    async def broadcast_safe_snapshots(self):
        for pid, viewer in list(self.players.items()):
            if viewer.writer.is_closing():
                continue
            visible_players = []
            visible_bullets = []

            for opid, other in self.players.items():
                if not other.alive:
                    continue
                if opid == pid:
                    visible_players.append({
                        "id": other.id,
                        "name": other.name,
                        "x": round(other.x, 2),
                        "y": round(other.y, 2),
                        "hp": other.hp,
                        "self": True,
                    })
                    continue
                if dist2(viewer.x, viewer.y, other.x, other.y) <= VIEW_DISTANCE * VIEW_DISTANCE and has_line_of_sight(viewer.x, viewer.y, other.x, other.y):
                    visible_players.append({
                        "id": other.id,
                        "name": other.name,
                        "x": round(other.x, 2),
                        "y": round(other.y, 2),
                        "hp": other.hp,
                        "self": False,
                    })

            for b in self.bullets.values():
                if dist2(viewer.x, viewer.y, b.x, b.y) <= VIEW_DISTANCE * VIEW_DISTANCE:
                    visible_bullets.append({
                        "id": b.id,
                        "x": round(b.x, 2),
                        "y": round(b.y, 2),
                    })

            msg = {
                "type": "snapshot",
                "you": pid,
                "tick": self.tick,
                "players": visible_players,
                "bullets": visible_bullets,
                "walls": WALLS,
                "world": {"w": WORLD_W, "h": WORLD_H},
            }
            try:
                await self.send(viewer.writer, msg)
            except Exception:
                pass

    async def handle_client(self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter):
        pid = str(uuid.uuid4())
        spawn_x = 100.0 + (len(self.players) % 10) * 60.0
        spawn_y = 100.0 + (len(self.players) // 10) * 60.0
        player = Player(id=pid, name=f"player_{pid[:6]}", writer=writer, x=spawn_x, y=spawn_y)

        async with self.lock:
            self.players[pid] = player

        try:
            await self.send(writer, {"type": "welcome", "id": pid, "tick_rate": TICK_RATE})
            while not reader.at_eof():
                line = await reader.readline()
                if not line:
                    break
                try:
                    msg = json.loads(line.decode().strip())
                except Exception:
                    continue

                mtype = msg.get("type")
                async with self.lock:
                    p = self.players.get(pid)
                    if p is None:
                        break

                    if mtype == "hello":
                        name = str(msg.get("name", "")).strip()
                        if name:
                            p.name = name[:24]

                    elif mtype == "input":
                        seq = int(msg.get("seq", 0))
                        if seq <= p.last_seq:
                            continue
                        p.last_seq = seq
                        move = msg.get("move", [0, 0])
                        aim = msg.get("aim", [p.aim_x, p.aim_y])
                        fire = bool(msg.get("fire", False))
                        mx = float(move[0]) if isinstance(move, list) and len(move) >= 2 else 0.0
                        my = float(move[1]) if isinstance(move, list) and len(move) >= 2 else 0.0
                        ax = float(aim[0]) if isinstance(aim, list) and len(aim) >= 2 else p.aim_x
                        ay = float(aim[1]) if isinstance(aim, list) and len(aim) >= 2 else p.aim_y
                        p.pending_input = {"move": (mx, my), "aim": (ax, ay), "fire": fire}
        finally:
            async with self.lock:
                self.players.pop(pid, None)
            try:
                writer.close()
                await writer.wait_closed()
            except Exception:
                pass

    def update_players(self, now: float):
        for p in self.players.values():
            if not p.alive:
                continue
            inp = p.pending_input
            mx, my = inp.get("move", (0.0, 0.0))
            mx, my = norm(mx, my)
            p.vx = mx * PLAYER_SPEED
            p.vy = my * PLAYER_SPEED

            ax, ay = inp.get("aim", (p.aim_x, p.aim_y))
            dx = ax - p.x
            dy = ay - p.y
            p.aim_x, p.aim_y = norm(dx, dy)

            nx = p.x + p.vx * DT
            ny = p.y + p.vy * DT
            p.x, p.y = move_with_collision(p.x, p.y, nx, ny)

            if inp.get("fire", False) and (now - p.last_fire) >= FIRE_COOLDOWN:
                p.last_fire = now
                bx = p.x + p.aim_x * (PLAYER_RADIUS + 6.0)
                by = p.y + p.aim_y * (PLAYER_RADIUS + 6.0)
                bullet = Bullet(
                    id=str(uuid.uuid4()),
                    owner_id=p.id,
                    x=bx,
                    y=by,
                    vx=p.aim_x * BULLET_SPEED,
                    vy=p.aim_y * BULLET_SPEED,
                    ttl=BULLET_LIFETIME,
                )
                self.bullets[bullet.id] = bullet

    def update_bullets(self):
        dead = []
        for bid, b in self.bullets.items():
            ox, oy = b.x, b.y
            b.x += b.vx * DT
            b.y += b.vy * DT
            b.ttl -= DT

            if b.ttl <= 0 or b.x < 0 or b.y < 0 or b.x > WORLD_W or b.y > WORLD_H:
                dead.append(bid)
                continue

            blocked = False
            for wx1, wy1, wx2, wy2 in WALLS:
                if segment_intersects_aabb(ox, oy, b.x, b.y, wx1, wy1, wx2, wy2):
                    blocked = True
                    break
            if blocked:
                dead.append(bid)
                continue

            for p in self.players.values():
                if not p.alive or p.id == b.owner_id:
                    continue
                if dist2(b.x, b.y, p.x, p.y) <= (PLAYER_RADIUS * PLAYER_RADIUS):
                    p.hp -= 25
                    if p.hp <= 0:
                        p.hp = 0
                        p.alive = False
                    dead.append(bid)
                    break

        for bid in dead:
            self.bullets.pop(bid, None)

    async def game_loop(self):
        while True:
            start = time.perf_counter()
            async with self.lock:
                self.tick += 1
                now = time.perf_counter()
                self.update_players(now)
                self.update_bullets()
                await self.broadcast_safe_snapshots()
            elapsed = time.perf_counter() - start
            await asyncio.sleep(max(0.0, DT - elapsed))

async def main():
    server = GameServer()
    tcp_server = await asyncio.start_server(server.handle_client, SERVER_HOST, SERVER_PORT)
    asyncio.create_task(server.game_loop())
    async with tcp_server:
        await tcp_server.serve_forever()

if __name__ == "__main__":
    asyncio.run(main())